import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import './Login.css';

function Login() {
  const [email, setEmail] = useState(""); 
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Freelancer"); 
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);

    try {
      const response = await fetch('http://localhost:3000/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, role }),
      });

      const data = await response.json();

      if (response.ok) {
        // ✅ Dashboard दिसण्यासाठी हे ३ डेटा सेव्ह होणे खूप महत्त्वाचे आहे
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user)); 
        localStorage.setItem('userRole', data.user.role);
        
        alert("Login Successful! 🎉");
        navigate("/dashboard"); // आता डॅशबोर्डवर नेईल
      } else {
        setError(data.msg || "Invalid Credentials");
      }
    } catch (error) {
      setError("Server शी संपर्क होत नाहीये. कृपया बॅकएंड चेक करा.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', background: '#f1f5f9' }}>
      <div style={{ background: 'white', padding: '40px', borderRadius: '15px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', width: '350px' }}>
        <h2 style={{ textAlign: 'center', color: '#1e293b', marginBottom: '20px' }}>{role} Login</h2>
        
        {error && (
          <div style={{ backgroundColor: '#fee2e2', color: '#ef4444', padding: '10px', borderRadius: '8px', marginBottom: '15px', textAlign: 'center', fontSize: '14px' }}>
            {error}
          </div>
        )}
        
        <form onSubmit={handleLogin}>
          <div style={{ marginBottom: '15px' }}>
            <label style={{ fontSize: '14px', fontWeight: 'bold', color: '#475569' }}>Select Role</label>
            <select 
              value={role} 
              onChange={(e) => setRole(e.target.value)} 
              style={{ width: '100%', padding: '10px', marginTop: '5px', borderRadius: '8px', border: '1px solid #cbd5e1', outline: 'none' }}
            >
              <option value="Freelancer">Freelancer</option>
              <option value="Client">Client (Hirer)</option>
            </select>
          </div>

          <div style={{ marginBottom: '15px' }}>
            <input 
              type="email" 
              placeholder="Email Address" 
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
              required 
              style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #cbd5e1', boxSizing: 'border-box', outline: 'none' }} 
            />
          </div>
          
          <div style={{ marginBottom: '20px' }}>
            <input 
              type="password" 
              placeholder="Password" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              required 
              style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #cbd5e1', boxSizing: 'border-box', outline: 'none' }} 
            />
          </div>

          <button 
            type="submit" 
            disabled={isLoading} 
            style={{ 
              width: '100%', 
              padding: '12px', 
              background: '#1e293b', 
              color: 'white', 
              border: 'none', 
              borderRadius: '8px', 
              cursor: 'pointer', 
              fontWeight: 'bold',
              transition: '0.3s'
            }}
          >
            {isLoading ? "Logging in..." : "Login Now"}
          </button>
        </form>
        
        <p style={{ textAlign: 'center', marginTop: '20px', fontSize: '14px', color: '#64748b' }}>
          Don't have an account? <span onClick={() => navigate("/signup")} style={{ color: '#38bdf8', cursor: 'pointer', fontWeight: 'bold' }}>Signup</span>
        </p>
      </div>
    </div>
  );
}

export default Login;
